import{_ as e,o as t,c as l,ag as i}from"./chunks/framework.sFGfN9OF.js";const h=JSON.parse('{"title":"秒杀系统设计","description":"","frontmatter":{},"headers":[],"relativePath":"system-design/seckill-system.md","filePath":"system-design/seckill-system.md","lastUpdated":1776563650000}'),s={name:"system-design/seckill-system.md"};function r(o,a,n,m,d,p){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="秒杀系统设计" tabindex="-1">秒杀系统设计 <a class="header-anchor" href="#秒杀系统设计" aria-label="Permalink to &quot;秒杀系统设计&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>在秒杀场景里，如何支撑瞬时高并发请求，同时保证库存不超卖、用户体验可接受？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>秒杀系统的核心矛盾是流量远大于库存和下游处理能力。常见思路是先在接入层做限流和静态化，把明显无效请求挡在外面；再通过消息队列削峰，把下单动作异步化；库存校验则前移到 Redis 或内存层，快速返回抢购结果。最终订单落库时，还要依赖数据库乐观锁或唯一约束兜底，避免并发写导致超卖。</p><p>系统设计不能只盯住“高并发”三个字，还要考虑链路隔离、热点容灾和可观测性。若某个服务异常，需要快速降级，而不是把整个核心交易链路拖垮。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>流量削峰依赖限流、排队和异步化。</li><li>库存扣减要有前置校验和数据库兜底。</li><li>关键链路要做隔离与降级。</li><li>压测和监控是上线前必须完成的工作。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>秒杀系统的关键不只是“扛住请求”，而是用分层治理把请求变得可控，再用一致性机制守住库存底线。</p>',10)])])}const u=e(s,[["render",r]]);export{h as __pageData,u as default};
